function getDayType(day) {
  switch (day) {
    case "Saturday":
    case "Sunday":            // 多个 case 共享同一段代码
      return "周末 🎉";
    case "Monday":
    case "Tuesday":
    case "Wednesday":
    case "Thursday":
    case "Friday":
      return "工作日 💼";
    default:
      return "未知日期";
  }
}

console.log(getDayType("Sunday"));  // "周末 🎉"
console.log(getDayType("Wednesday"));  // "工作日 💼"

// for (初始化; 条件; 更新) { 循环体 }
for (let i = 0; i < 5; i++) {
  console.log(`第 ${i} 次`);
}
// 输出: 第 0 次、第 1 次、第 2 次、第 3 次、第 4 次

// 数组求和
const arr = [1, 2, 3, 4];
let sum = 0;
for (let i = 0; i < arr.length; i++) {
  sum += arr[i];
}
console.log(sum);  // 10

// 倒计时：条件未知次数
let n = 3;
while (n > 0) {
  console.log(n);  // 3, 2, 1
  n--;
}

// ⚠️ 死循环警告：while(true) 必须有 break 出口
while (true) {
  const input = getInput();
  if (input === "exit") break;
  process(input);
}

// 至少询问一次用户输入
let input;
do {
  input = getInput();
  console.log(`你输入了: ${input}`);
} while (input !== "exit");
// 即使第一次就输入 "exit"，也会先执行一次循环体

