const user = { name: "小明", age: 20, role: "dev" };
for (const key in user) {
  if (user.hasOwnProperty(key)) {  // 过滤原型链属性
    console.log(`${key}: ${user[key]}`);
  }
}
// name: 小明、age: 20、role: dev

// 找到第一个偶数就停止
for (let i = 0; i < 10; i++) {
  if (i % 2 === 0) {
    console.log(`找到偶数: ${i}`);
    break;  // 跳出整个循环
  }
}
// 输出: 找到偶数: 0（立即停止）

// 跳过偶数，只打印奇数
for (let i = 0; i < 10; i++) {
  if (i % 2 === 0) continue;  // 跳过本次
  console.log(i);  // 1, 3, 5, 7, 9
}

// 嵌套循环里需要"一次跳多层"
outer:
for (let i = 0; i < 3; i++) {
  for (let j = 0; j < 3; j++) {
    if (i === 1 && j === 1) {
      break outer;  // 跳出两层循环
    }
    console.log(`i=${i}, j=${j}`);
  }
}
// 输出: i=0,j=0 / i=0,j=1 / i=0,j=2 / i=1,j=0
